import { useState, useEffect } from 'react';
import { useKaTeX } from '../hooks/useKaTeX.js';
import { latexNum, clamp, clampProb } from '../utils/math.js';

/**
 * Discrete probability calculator.
 * Shows P(X = x), P(X ≤ x), P(X ≥ x), and quantile.
 */
export function DiscreteCalculator({ page, params, cache, getCdf, getQuantile }) {
  const [x, setX] = useState(() => cache.displaySupport[0]);
  const [pL, setPL] = useState(0.95);

  // Reset x when the display range changes (e.g. after parameter update)
  const [a, b] = cache.displaySupport;
  useEffect(() => {
    setX(prev => clamp(Math.round(prev), a, b));
  }, [a, b]);

  const varSym = page?.variableSymbol || 'X';
  const valSym = page?.valueSymbol    || 'x';

  const { pmf } = cache;
  const xClamped = clamp(Math.round(x), a, b);
  const idx       = xClamped - a;
  const pmfVal    = (idx >= 0 && idx < pmf.length) ? pmf[idx] : (page?.pmf?.(xClamped, params) || 0);
  const cdfVal    = getCdf(xClamped);
  const ccdfVal   = clampProb(1 - getCdf(xClamped - 1));
  const qVal      = getQuantile(pL);

  const rCode = page?.rCode ?? {};

  const katexRef = useKaTeX([x, pL, pmfVal, cdfVal, ccdfVal, qVal, varSym, valSym]);

  return (
    <div className="calc-wrap" ref={katexRef}>
      <div className="sec-label">Calculator</div>
      <div className="calc-panels">

        {/* ── PMF / CDF panel ── */}
        <div className="calc-panel">
          <div className="calc-input-row">
            <label>{'$' + valSym + '$'}</label>
            <input
              type="range"
              min={a} max={b} step={1}
              value={xClamped}
              onChange={e => setX(parseInt(e.target.value, 10))}
            />
            <input
              type="number"
              min={a} max={b} step={1}
              value={xClamped}
              onChange={e => {
                const v = parseInt(e.target.value, 10);
                if (Number.isFinite(v)) setX(v);
              }}
            />
          </div>
          <div className="calc-results">
            <div className="calc-result-row">
              <div className="calc-result-top">
                <div className="calc-result-meaning">
                  {'$P(' + varSym + ' = ' + xClamped + ')$'}
                </div>
                <div className="calc-result-value">
                  <span className="result-val">{latexNum(pmfVal, 4)}</span>
                </div>
              </div>
              {rCode.pmf && (
                <div className="calc-code-row">
                  <span className="calc-code-inline" dangerouslySetInnerHTML={{ __html: rCode.pmf(params) }} />
                </div>
              )}
            </div>

            <div className="calc-result-row">
              <div className="calc-result-top">
                <div className="calc-result-meaning">
                  {'$P(' + varSym + ' \\le ' + xClamped + ')$'}
                </div>
                <div className="calc-result-value">
                  <span className="result-val">{latexNum(cdfVal, 4)}</span>
                </div>
              </div>
              {rCode.cdf && (
                <div className="calc-code-row">
                  <span className="calc-code-inline" dangerouslySetInnerHTML={{ __html: rCode.cdf(params) }} />
                </div>
              )}
            </div>

            <div className="calc-result-row">
              <div className="calc-result-top">
                <div className="calc-result-meaning">
                  {'$P(' + varSym + ' \\ge ' + xClamped + ')$'}
                </div>
                <div className="calc-result-value">
                  <span className="result-val">{latexNum(ccdfVal, 4)}</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* ── Quantile panel ── */}
        <div className="calc-panel">
          <div className="calc-input-row">
            <label>$p_L$</label>
            <input
              type="range"
              min={0} max={1} step={0.001}
              value={pL}
              onChange={e => setPL(parseFloat(e.target.value))}
            />
            <input
              type="number"
              min={0} max={1} step={0.001}
              value={pL}
              onChange={e => {
                const v = parseFloat(e.target.value);
                if (Number.isFinite(v)) setPL(clamp(v, 0, 1));
              }}
            />
          </div>
          <div className="calc-results">
            <div className="calc-result-row">
              <div className="calc-result-top">
                <div className="calc-result-meaning">
                  {'Smallest $' + valSym + '$ such that $P(' + varSym + '\\le ' + valSym + ')\\ge p_L = ' + latexNum(pL, 4) + '$'}
                </div>
                <div className="calc-result-value">
                  <span className="result-val">
                    {qVal === Infinity ? '∞' : String(qVal)}
                  </span>
                </div>
              </div>
              {rCode.q && (
                <div className="calc-code-row">
                  <span className="calc-code-inline" dangerouslySetInnerHTML={{ __html: rCode.q(params) }} />
                </div>
              )}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

import { useRef, useEffect, useCallback } from 'react';
import { latexNum, clamp } from '../utils/math.js';

// Draw helpers ----------------------------------------------------------------

function drawAxes(ctx, W, H, L, R, T, B, yMax) {
  const gW = W - L - R;
  const gH = H - T - B;

  ctx.strokeStyle = '#ccc';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(L, H - B);
  ctx.lineTo(W - R, H - B);
  ctx.moveTo(L, T);
  ctx.lineTo(L, H - B);
  ctx.stroke();

  ctx.font = '10px sans-serif';
  ctx.textAlign = 'right';

  for (let i = 0; i <= 5; i++) {
    const y   = H - B - (i / 5) * gH;
    const val = (i / 5) * yMax;
    ctx.fillStyle = '#999';
    ctx.fillText(latexNum(val, 2), L - 5, y + 3);

    ctx.strokeStyle = '#eee';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(L, y);
    ctx.lineTo(W - R, y);
    ctx.stroke();
  }
}

function drawPMFBars(ctx, cache, selectedXs, minX, maxX, yMax, W, H, L, R, T, B) {
  const gW = W - L - R;
  const gH = H - T - B;
  const range = Math.max(1, maxX - minX + 1);
  const step  = gW / range;
  const barW  = Math.max(1, step * 0.7);
  const [cacheA] = cache.displaySupport;

  for (let x = minX; x <= maxX; x++) {
    const idx = x - cacheA;
    const p   = (idx >= 0 && idx < cache.pmf.length) ? cache.pmf[idx] : 0;
    const barH = (p / yMax) * gH;
    const px   = L + (x - minX) * step + (step - barW) / 2;
    const selected = selectedXs.has(x);
    ctx.fillStyle = selected ? '#045275' : 'rgba(4,82,117,.30)';
    ctx.fillRect(px, H - B - barH, barW, barH);
  }
}

function drawCDFStep(ctx, cache, minX, maxX, yMax, W, H, L, R, T, B) {
  const gW = W - L - R;
  const gH = H - T - B;
  const range = Math.max(1, maxX - minX + 1);
  const step  = gW / range;
  const [cacheA] = cache.displaySupport;

  const xAtValue = x => L + (x - minX + 0.5) * step;
  const xBefore  = x => xAtValue(x) - step / 2;
  const xAfter   = x => xAtValue(x) + step / 2;
  const yToPx    = y => H - B - (y / yMax) * gH;

  const getCdf = (x) => {
    const idx = x - cacheA;
    return (idx >= 0 && idx < cache.cdf.length) ? cache.cdf[idx] : 0;
  };

  ctx.save();
  ctx.strokeStyle = '#e11d48';
  ctx.fillStyle   = '#e11d48';
  ctx.lineWidth   = 2;

  const y0 = yToPx(0);
  ctx.beginPath();
  ctx.moveTo(xBefore(minX), y0);
  ctx.lineTo(xAtValue(minX), y0);
  ctx.stroke();

  for (let x = minX; x <= maxX; x++) {
    const Fprev = x > cacheA ? getCdf(x - 1) : 0;
    const Fx    = getCdf(x);
    const x0    = xAtValue(x);
    const xl    = xBefore(x);
    const xr    = xAfter(x);
    const yPrev = yToPx(Fprev);
    const yNow  = yToPx(Fx);

    if (x > minX) {
      ctx.beginPath();
      ctx.moveTo(xl, yPrev);
      ctx.lineTo(x0, yPrev);
      ctx.stroke();
    }

    ctx.beginPath();
    ctx.moveTo(x0, yNow);
    ctx.lineTo(xr, yNow);
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(x0, yPrev, 2.8, 0, Math.PI * 2);
    ctx.fillStyle = '#fff';
    ctx.fill();
    ctx.strokeStyle = '#e11d48';
    ctx.stroke();

    ctx.beginPath();
    ctx.arc(x0, yNow, 2.8, 0, Math.PI * 2);
    ctx.fillStyle = '#e11d48';
    ctx.fill();

    ctx.strokeStyle = '#e11d48';
  }

  const xR1 = xAfter(maxX);
  const xR2 = Math.min(W - R, xR1 + step / 2);
  ctx.beginPath();
  ctx.moveTo(xR1, yToPx(getCdf(maxX)));
  ctx.lineTo(xR2, yToPx(getCdf(maxX)));
  ctx.stroke();

  ctx.restore();
}

function drawXLabels(ctx, minX, maxX, W, H, L, R, T, B) {
  const gW   = W - L - R;
  const range = Math.max(1, maxX - minX + 1);
  const step  = gW / range;
  const jump  = range <= 20 ? 1 : Math.ceil(range / 10);

  ctx.fillStyle = '#666';
  ctx.font      = '10px sans-serif';
  ctx.textAlign = 'center';

  for (let x = minX; x <= maxX; x++) {
    if ((x - minX) % jump === 0) {
      const px = L + (x - minX + 0.5) * step;
      ctx.fillText(String(x), px, H - B + 13);
    }
  }
}

